import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Home, User, PlusSquare, Settings, 
  Heart, Share2, Search, Bell, MapPin, 
  LogOut, Moon, Sun, Flag,
  Play, Pause, Award, CheckCircle, Loader2, Video as VideoIcon,
  X, Camera, Volume2, VolumeX,
  Link as LinkIcon, AlertCircle,
  Send, Wand2, Type, Scissors, Sliders, HelpCircle,
  RotateCw, FlipHorizontal, Gauge, Plus, Trash2, Download,
  Sparkles, RefreshCw, ThumbsUp, ThumbsDown, Lock, Crosshair,
  Maximize2, Minimize2, Globe, Film, Image as ImageIcon,
  Cone, Mic, Music, Bookmark, PictureInPicture, Zap, Mail, Calendar, Info
} from 'lucide-react';
import { User as UserType, Video, VideoEditingMetadata, TextLayer, AudioLayer, VideoAdjustments, VideoTransform } from './types';
import Subscription, { PlanType } from './components/Subscription';
import Support from './components/Support';
import { getAIVideoIdeas, getAIEditingSuggestions, generateAIVideo, generateSpeech } from './services/geminiService';
