               </div>
               <div className="flex gap-3"><button onClick={() => setShowAiGenerator(false)} className="flex-1 py-3 bg-gray-800 rounded-xl font-bold text-gray-300">{TRANSLATIONS[selectedLanguage].cancel}</button>
