const VideoCard: React.FC<{ 
  video: Video; 
  isActive: boolean; 
  onTogglePlay: () => void;
  user: UserType | undefined;
  onInteraction: (type: 'like' | 'share' | 'comment' | 'bookmark') => void;
  onReport: () => void;
  onRequestShare: () => void;
  lang: LanguageCode;
  isBookmarked: boolean;
}> = ({ video, isActive, onTogglePlay, user, onInteraction, onReport, onRequestShare, lang, isBookmarked }) => {
  const [liked, setLiked] = useState(false);
  const [bookmarked, setBookmarked] = useState(isBookmarked);
  const [hasError, setHasError] = useState(false);
  const [showHeartAnimation, setShowHeartAnimation] = useState(false);
  const lastTapRef = useRef<number>(0);
  const t = TRANSLATIONS[lang];

  useEffect(() => { setHasError(false); }, [video.id]);

  const handleDoubleTap = (e: React.MouseEvent) => {
    const now = Date.now();
    if (now - lastTapRef.current < 300) {
      if (!liked) { setLiked(true); onInteraction('like'); }
      setShowHeartAnimation(true);
      setTimeout(() => setShowHeartAnimation(false), 1000);
    } 
    lastTapRef.current = now;
  };

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    setLiked(!liked);
    if (!liked) onInteraction('like');
  };

  const handleBookmark = (e: React.MouseEvent) => {
    e.stopPropagation();
    setBookmarked(!bookmarked);
    onInteraction('bookmark');
  };

  const handleError = () => setHasError(true);

  const handleNativeShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Videos App',
          text: video.description || 'Check out this video!',
          url: APP_SHARE_URL
        });
        onInteraction('share');
      } catch (err) {
        console.error("Share failed", err);
        onRequestShare(); // Fallback to custom share
      }
    } else {
      onRequestShare();
    }
  };

  if (hasError || !video.url) {
    return (
      <div className="relative w-full h-full snap-center bg-gray-900 flex flex-col items-center justify-center text-white p-6 text-center">
        <div className="w-16 h-16 bg-primary/20 rounded-full flex items-center justify-center mb-4">
           <AlertCircle size={32} className="text-primary" />
        </div>
        <h3 className="text-lg font-bold">Video Unavailable</h3>
        <p className="text-xs text-gray-500 mt-2">Expired source or unsupported format</p>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full snap-center bg-black overflow-hidden" onClick={handleDoubleTap}>
      {showHeartAnimation && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30 animate-bounce">
            <Heart size={100} className="text-white fill-red-500 drop-shadow-2xl opacity-90" />
         </div>
      )}
      <div className="w-full h-full">
        <VLCPlayer
          src={video.url}
          poster={video.thumbnail}
          shouldPlay={isActive}
          className="w-full h-full"
          style={{ 
            filter: video.editData ? buildFilterString(video.editData.filter, video.editData.adjustments) : 'none',
            transform: video.editData ? buildTransformString(video.editData.transform) : 'none'
          }}
          trim={video.editData?.trim}
          audioLayers={video.editData?.audioLayers}
          loop={true}
          onError={handleError}
        />
        {video.editData?.textLayers?.map((layer) => (
          <div key={layer.id} className="absolute pointer-events-none whitespace-nowrap z-10" style={{ top: `${layer.y}%`, left: `${layer.x}%`, transform: 'translate(-50%, -50%)', color: layer.color, fontSize: `${layer.fontSize}px`, textShadow: '1px 1px 2px black', backgroundColor: layer.backgroundColor || 'transparent', padding: '4px 8px', borderRadius: '4px' }}>
            <span className="font-bold">{layer.text}</span>
          </div>
        ))}
      </div>
      {video.hasWatermark && (!user || !user.isPremium) && (
        <div className="absolute top-20 right-4 z-20 bg-black/60 backdrop-blur-md px-3 py-1 rounded-full border border-white/20 pointer-events-none">
          <div className="flex items-center gap-1.5">
            <Sparkles size={12} className="text-primary" />
            <span className="text-[10px] text-white font-medium">{t.watermark}</span>
          </div>
        </div>
      )}
      <div className="absolute bottom-[20px] left-0 right-0 p-4 pointer-events-none z-20">
        <div className="flex justify-between items-end pb-12">
          <div className="text-white flex-1 mr-12 rtl:mr-0 rtl:ml-12 text-left rtl:text-right drop-shadow-md">
            <div className="flex items-center gap-2 mb-2">
                <h3 className="font-bold text-lg cursor-pointer hover:underline">@{user?.username || 'unknown'}</h3>
                {user?.isVerified && <span className="bg-blue-500 text-[10px] px-1 rounded-full text-white">✓</span>}
            </div>
            <p className="text-sm line-clamp-2 mb-2">{video.description}</p>
            <div className="flex gap-2 text-xs opacity-90 mb-2 flex-wrap">
               {video.tags.map(t => <span key={t} className="font-bold text-primary">#{t}</span>)}
            </div>
          </div>
          <div className="flex flex-col gap-6 items-center min-w-[50px] pointer-events-auto">
            <div className="relative group cursor-pointer">
               <img src={user?.avatar || createFallbackThumbnail('User')} alt="avatar" className="w-12 h-12 rounded-full border-2 border-white object-cover" />
            </div>
            <button onClick={handleLike} className="flex flex-col items-center gap-1 group">
              <div className={`p-2 transition transform active:scale-90 ${liked ? 'text-red-500' : 'text-white'}`}>
                <Heart fill={liked ? "currentColor" : "white"} size={32} className={liked ? "" : "opacity-90"} />
              </div>
              <span className="text-white text-xs font-bold drop-shadow-md">{video.likes + (liked ? 1 : 0)}</span>
            </button>
            <button onClick={handleNativeShare} className="flex flex-col items-center gap-1 group">
               <div className="p-2 transition transform active:scale-90 text-white">
                 <Share2 size={32} fill="white" className="opacity-90" />
               </div>
               <span className="text-white text-xs font-bold drop-shadow-md">{video.shares}</span>
            </button>
            <button onClick={handleBookmark} className="flex flex-col items-center gap-1 group">
               <div className={`p-2 transition transform active:scale-90 ${bookmarked ? 'text-yellow-400' : 'text-white'}`}>
                 <Bookmark size={32} fill={bookmarked ? "currentColor" : "none"} className="opacity-90" />
               </div>
            </button>
            <button onClick={onReport} className="flex flex-col items-center gap-1 group opacity-60 hover:opacity-100">
               <div className="p-2 text-white"><Flag size={20} /></div>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Auth Component ---
const AuthScreen: React.FC<{ onLogin: (u: UserType) => void, lang: LanguageCode, setLang: (l: LanguageCode) => void }> = ({ onLogin, lang, setLang }) => {
   const [form, setForm] = useState({
     fullName: '', username: '', email: '', password: '', dob: '', gender: 'Other' as UserType['gender'], location: '', avatar: ''
   });
   const [detecting, setDetecting] = useState(false);
   const t = TRANSLATIONS[lang];

   const handleLocation = () => {
     setDetecting(true);
     navigator.geolocation.getCurrentPosition(
       (pos) => {
         setForm({ ...form, location: `${pos.coords.latitude.toFixed(2)}, ${pos.coords.longitude.toFixed(2)}` });
         setDetecting(false);
       },
       () => setDetecting(false)
     );
   };

   const handlePhoto = async (e: React.ChangeEvent<HTMLInputElement>) => {
     if (e.target.files?.[0]) {
       const reader = new FileReader();
       reader.onload = (ev) => setForm({ ...form, avatar: ev.target?.result as string });
       reader.readAsDataURL(e.target.files[0]);
     }
   };

   const handleSubmit = (e: React.FormEvent) => {
     e.preventDefault();
     if (!form.username || !form.fullName) return;
     onLogin({
       id: Math.random().toString(36).substr(2, 9),
       ...form,
       points: 100,
       isVerified: false,
       videoCount: 0,
       isPremium: false,
       bookmarks: []
     });
   };

   return (
     <div className="h-full flex flex-col items-center bg-white dark:bg-black overflow-y-auto px-6 py-10">
        <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mb-4 shadow-xl shadow-primary/30">
           <Play size={32} fill="white" className="ml-1" />
        </div>
        <h1 className="text-2xl font-bold text-primary mb-2">Videos</h1>
        <p className="text-gray-500 text-sm mb-8">{t.welcome}</p>

        <form onSubmit={handleSubmit} className="w-full max-w-sm space-y-4">
           <div className="flex justify-center mb-6">
              <label className="relative cursor-pointer group">
                 <div className="w-24 h-24 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center overflow-hidden border-2 border-primary/20 group-hover:border-primary transition">
                    {form.avatar ? <img src={form.avatar} className="w-full h-full object-cover" /> : <Camera size={32} className="text-gray-400" />}
                 </div>
                 <div className="absolute bottom-0 right-0 bg-primary text-white p-1.5 rounded-full shadow-lg"><Plus size={16}/></div>
                 <input type="file" hidden accept="image/*" onChange={handlePhoto} />
              </label>
           </div>

           <div className="space-y-3">
              <div className="relative">
                 <User size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input value={form.fullName} onChange={e => setForm({...form, fullName: e.target.value})} placeholder={t.fullName} required className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="relative">
                 <AtSign size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input value={form.username} onChange={e => setForm({...form, username: e.target.value})} placeholder={t.username} required className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="relative">
                 <Mail size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} placeholder={t.email} required className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="relative">
                 <Calendar size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input type="date" value={form.dob} onChange={e => setForm({...form, dob: e.target.value})} placeholder={t.dob} className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="flex gap-2">
                 <select value={form.gender} onChange={e => setForm({...form, gender: e.target.value as any})} className="flex-1 px-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl outline-none text-sm">
                    <option value="Male">{t.male || 'Male'}</option>
                    <option value="Female">{t.female || 'Female'}</option>
                    <option value="Other">{t.other || 'Other'}</option>
                 </select>
                 <button type="button" onClick={handleLocation} className="p-2.5 bg-gray-100 dark:bg-gray-800 rounded-xl text-primary hover:bg-gray-200 transition">
                    {detecting ? <Loader2 size={20} className="animate-spin" /> : <MapPin size={20}/>}
                 </button>
              </div>
           </div>

           <button type="submit" className="w-full py-3.5 bg-primary text-white rounded-xl font-bold shadow-lg shadow-primary/20 hover:bg-blue-800 transition">
              {t.createAccount}
           </button>
        </form>

        <div className="mt-10">
           <select value={lang} onChange={e => setLang(e.target.value as any)} className="bg-gray-100 dark:bg-gray-800 px-4 py-2 rounded-full text-xs">
              {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.native}</option>)}
           </select>
        </div>
     </div>
   );
};

const AtSign = ({ size, className }: any) => (
