const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserType | undefined>(() => {
    const saved = localStorage.getItem('currentUser');
    if (!saved || saved === 'undefined') return undefined;
    try {
      return JSON.parse(saved);
    } catch (e) {
      console.warn("Auth initialization error", e);
      return undefined;
    }
  });

  const [videos, setVideos] = useState<Video[]>([]);
  const [activeTab, setActiveTab] = useState('home');
  const [showUploadMenu, setShowUploadMenu] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showAiGenerator, setShowAiGenerator] = useState(false);
  const [editorFile, setEditorFile] = useState<File | null>(null);
  const [selectedLanguage, setSelectedLanguage] = useState<LanguageCode>('en');
  const [aiIdeaPrompt, setAiIdeaPrompt] = useState<string | undefined>();

  const [aiPrompt, setAiPrompt] = useState('');
  const [aiStyle, setAiStyle] = useState('Cinematic');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [showPolicy, setShowPolicy] = useState<{title: string, content: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const browserLang = navigator.language.split('-')[0] as LanguageCode;
    if (TRANSLATIONS[browserLang]) setSelectedLanguage(browserLang);
  }, []);

  useEffect(() => {
    document.documentElement.dir = selectedLanguage === 'ar' ? 'rtl' : 'ltr';
  }, [selectedLanguage]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [currentUser]);

  const handlePublishVideo = async (metadata: VideoEditingMetadata, isAI: boolean) => {
    if (!editorFile || !currentUser) return;
    try {
      const thumbnail = await generateThumbnail(editorFile);
      const blobUrl = URL.createObjectURL(editorFile); 
      const newVideo: Video = {
        id: Date.now().toString(),
        userId: currentUser.id,
        url: blobUrl,
        thumbnail,
        type: 'short',
        description: aiIdeaPrompt || (isAI ? "AI Generated Masterpiece" : "My awesome new video"),
        views: 0, likes: 0, shares: 0, commentsCount: 0,
        tags: isAI ? ['AI', 'Generated'] : ['New', 'Creative'],
        createdAt: new Date().toISOString(),
        editData: { ...metadata, isAIGenerated: isAI },
        hasWatermark: isAI
      };
      setVideos(prev => [newVideo, ...prev]);
      setCurrentUser({ ...currentUser, videoCount: currentUser.videoCount + 1, points: currentUser.points + (isAI ? 5 : 10) });
      setShowEditor(false);
      setEditorFile(null);
      setAiIdeaPrompt(undefined);
    } catch (e) { console.error("Publishing error", e); }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (!file.type.startsWith('video/')) {
        alert("Please select a valid video file.");
        return;
      }
      setEditorFile(file);
      setShowEditor(true);
      setShowUploadMenu(false);
      e.target.value = '';
    }
  };

  if (!currentUser) {
    return <AuthScreen onLogin={setCurrentUser} lang={selectedLanguage} setLang={setSelectedLanguage} />;
  }

  return (
    <div className="flex flex-col h-screen bg-white dark:bg-black text-gray-900 dark:text-gray-100 overflow-hidden">
      {activeTab === 'home' && (
        <header className="absolute top-0 left-0 right-0 z-40 p-4 bg-gradient-to-b from-black/80 to-transparent flex justify-between items-center text-white">
           <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center"><Play size={16} fill="white" /></div>
              <span className="font-bold text-lg tracking-tight">Videos</span>
           </div>
           <div className="flex gap-4"><button><Search size={24} /></button><button><Bell size={24} /></button></div>
        </header>
      )}

      <main className="flex-1 overflow-hidden relative">
        {activeTab === 'home' && (
          <div className="h-full w-full snap-y-mandatory overflow-y-scroll no-scrollbar">
            {videos.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-500 gap-4 p-10 text-center">
                  <div className="w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center animate-pulse"><Play size={40} className="text-primary ml-1" /></div>
                  <p>{TRANSLATIONS[selectedLanguage].noVideos}</p>
                  <button onClick={() => setShowUploadMenu(true)} className="px-6 py-2 bg-primary text-white rounded-full font-bold shadow-lg">{TRANSLATIONS[selectedLanguage].beFirst}</button>
               </div>
            ) : (
              videos.map((v) => (
                <div key={v.id} className="h-full w-full snap-center">
                   <VideoCard video={v} isActive={true} onTogglePlay={() => {}} user={currentUser} onInteraction={() => {}} onReport={() => {}} onRequestShare={() => {}} lang={selectedLanguage} isBookmarked={currentUser.bookmarks?.includes(v.id)} />
                </div>
              ))
            )}
          </div>
        )}
        {activeTab === 'discover' && <div className="h-full overflow-y-auto p-4 bg-gray-50 dark:bg-black text-center py-20"><Search size={48} className="mx-auto mb-2 opacity-50"/><p>{TRANSLATIONS[selectedLanguage].discover}</p></div>}
        {activeTab === 'profile' && <ProfilePage user={currentUser} videos={videos.filter(v => v.userId === currentUser.id)} lang={selectedLanguage} onLogout={() => setCurrentUser(undefined)} onShowPolicy={setShowPolicy} />}
        {activeTab === 'support' && <div className="h-full p-4 bg-gray-50 dark:bg-black overflow-y-auto"><Support userName={currentUser.username} /></div>}
      </main>

      <nav className="h-16 bg-white dark:bg-black border-t border-gray-200 dark:border-gray-800 flex justify-around items-center z-50">
         <NavBtn icon={Home} label={TRANSLATIONS[selectedLanguage].home} active={activeTab === 'home'} onClick={() => setActiveTab('home')} />
         <NavBtn icon={Search} label={TRANSLATIONS[selectedLanguage].search} active={activeTab === 'discover'} onClick={() => setActiveTab('discover')} />
         <div className="relative -top-4"><button onClick={() => setShowUploadMenu(true)} className="w-14 h-14 bg-gradient-to-tr from-primary to-blue-400 rounded-full flex items-center justify-center text-white shadow-lg"><Plus size={32} /></button></div>
         <NavBtn icon={HelpCircle} label={TRANSLATIONS[selectedLanguage].support} active={activeTab === 'support'} onClick={() => setActiveTab('support')} />
         <NavBtn icon={User} label={TRANSLATIONS[selectedLanguage].profile} active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} />
      </nav>

      {showUploadMenu && (
         <div className="fixed inset-0 z-[60] bg-black/80 flex items-end animate-fade-in">
            <div className="w-full bg-white dark:bg-card rounded-t-2xl p-6 pb-10 space-y-4">
               <div className="flex justify-between items-center mb-2"><h3 className="font-bold text-lg">{TRANSLATIONS[selectedLanguage].create}</h3><button onClick={() => setShowUploadMenu(false)}><X/></button></div>
               <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center gap-4 px-4"><div className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center text-white"><ImageIcon/></div><div className="text-left"><div className="font-bold">{TRANSLATIONS[selectedLanguage].uploadFromGallery}</div><div className="text-xs text-gray-500">Edit existing videos</div></div></button>
               <button onClick={() => { setShowUploadMenu(false); setShowAiGenerator(true); }} className="w-full py-4 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center gap-4 px-4"><div className="w-10 h-10 bg-purple-500 rounded-full flex items-center justify-center text-white"><Sparkles/></div><div className="text-left"><div className="font-bold">{TRANSLATIONS[selectedLanguage].generateAiVideo}</div><div className="text-xs text-gray-500">Create from text prompt</div></div></button>
               <input type="file" ref={fileInputRef} className="hidden" accept="video/*" onChange={handleFileSelect} />
            </div>
         </div>
      )}

      {showEditor && editorFile && (
         <VideoEditor file={editorFile} onSave={handlePublishVideo} onCancel={() => { setShowEditor(false); setEditorFile(null); }} lang={selectedLanguage} initialPrompt={aiIdeaPrompt} />
      )}

      {showAiGenerator && (
         <div className="fixed inset-0 z-[60] bg-black/90 flex items-center justify-center p-4">
