import { GoogleGenAI, Modality } from "@google/genai";
import { SUPPORT_EMAIL } from '../constants';

// For Basic Text Tasks like support and suggestions, use gemini-3-flash-preview.
const TEXT_MODEL = 'gemini-3-flash-preview';

export const getSupportResponse = async (userQuery: string, userName: string, language: string = 'English'): Promise<string> => {
  try {
    // Re-initialize to handle dynamic API key selection if needed
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const systemInstruction = `
      You are the AI Support Agent for "Videos" app.
      Help user "${userName}".
      Reply in ${language} language.
      If technical issue, refer to ${SUPPORT_EMAIL}.
      Keep answers short and helpful.
    `;

    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: userQuery,
      config: { systemInstruction },
    });

    return response.text || "I'm having trouble connecting right now.";
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    console.error("Gemini Error:", errorMessage);
    return `Error. Contact ${SUPPORT_EMAIL}.`;
  }
};

export const getAIVideoIdeas = async (language: string = 'English'): Promise<string[]> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const prompt = `Give me 3 short, viral video ideas for a content creator. Output must be in ${language} language. Return ONLY a raw JSON array of strings, no markdown.`;

    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: prompt,
      config: { responseMimeType: 'application/json' }
    });

    const text = response.text || '[]';
    // Trim and parse text directly
    return JSON.parse(text.trim());
  } catch (e) {
    const errorMessage = e instanceof Error ? e.message : String(e);
    console.error("AI Ideas Error", errorMessage);
    return ["Review a gadget", "Cook a simple meal", "Tell a funny story"];
  }
};

export const getAIEditingSuggestions = async (currentDuration: number, language: string = 'English'): Promise<{
  suggestion: string;
  type: 'filter' | 'trim' | 'music';
  data: any;
}> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const prompt = `
      Analyze a video context with duration ${currentDuration}s.
      Suggest ONE creative edit to improve it.
      The suggestion text must be in ${language} language.
      Return JSON: { "suggestion": "short reason in ${language}", "type": "filter|trim|music", "data": "value" }.
      For 'filter', data is a CSS filter string (e.g. 'sepia(80%)').
      For 'trim', data is { "start": 0, "end": ${Math.max(1, Math.floor(currentDuration * 0.8))} }.
      For 'music', data is a genre string.
    `;

    const response = await ai.models.generateContent({
      model: TEXT_MODEL,
      contents: prompt,
      config: { responseMimeType: 'application/json' }
    });

    const text = response.text || '{}';
    return JSON.parse(text.trim());
  } catch (e) {
    return {
      suggestion: "Apply a vintage look for a nostalgic feel.",
      type: "filter",
      data: "sepia(60%) contrast(110%)"
    };
  }
};

export const generateAIVideo = async (prompt: string, style: string): Promise<Blob | null> => {
  try {
    const apiKey = process.env.API_KEY || '';
    if (!apiKey) throw new Error("API Key missing");

    // CRITICAL: Re-initialize right before Veo calls to catch potential key updates
    const ai = new GoogleGenAI({ apiKey });

    const augmentedPrompt = `${prompt}. Style: ${style}, high quality, cinematic lighting.`;

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: augmentedPrompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9' 
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({operation: operation});
    }

    const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!videoUri) throw new Error("No video generated");

    const response = await fetch(`${videoUri}&key=${apiKey}`);
    if (!response.ok) throw new Error("Failed to download generated video");

    return await response.blob();

  } catch (e) {
    const errorMessage = e instanceof Error ? e.message : String(e);
    console.error("Video Generation Error:", errorMessage);
    return null;
  }
};

export const generateSpeech = async (text: string, voiceName: string = 'Kore'): Promise<Blob | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName }
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio generated");

    // Decoding Base64 into raw PCM bytes as returned by the API.
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    // Return raw PCM bytes; label correctly so consumers know how to handle it (though standard audio tags need a wrapper).
    return new Blob([bytes], { type: 'audio/pcm;rate=24000' });

  } catch (e) {
    const errorMessage = e instanceof Error ? e.message : String(e);
    console.error("TTS Generation Error:", errorMessage);
    return null;
  }
};

