// --- Helpers ---
const createFallbackThumbnail = (text: string = 'Video') => {
  const canvas = document.createElement('canvas');
  canvas.width = 400;
  canvas.height = 600;
  const ctx = canvas.getContext('2d');
  if (ctx) {
    ctx.fillStyle = '#1e1e1e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.beginPath();
    ctx.arc(200, 250, 60, 0, 2 * Math.PI);
    ctx.fillStyle = '#333';
    ctx.fill();
    ctx.beginPath();
    ctx.moveTo(185, 220);
    ctx.lineTo(235, 250);
    ctx.lineTo(185, 280);
    ctx.fillStyle = '#555';
    ctx.fill();
    ctx.fillStyle = '#666';
    ctx.font = 'bold 30px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(text, 200, 360);
  }
  return canvas.toDataURL('image/jpeg', 0.6);
};

const generateThumbnail = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const video = document.createElement('video');
    const url = URL.createObjectURL(file);
    video.src = url;
    video.crossOrigin = 'anonymous';
    video.muted = true;
    video.playsInline = true;
    video.preload = 'metadata';
    video.currentTime = 0.5;

    const onSeeked = () => {
      const canvas = document.createElement('canvas');
      canvas.width = 400;
      const aspect = video.videoHeight / video.videoWidth;
      canvas.height = 400 * (aspect || 1.5);
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg', 0.7));
      } else {
        resolve(createFallbackThumbnail('Preview'));
      }
      cleanup();
    };

    const onError = () => {
      resolve(createFallbackThumbnail('Error'));
      cleanup();
    };

    const cleanup = () => {
       video.removeEventListener('seeked', onSeeked);
       video.removeEventListener('error', onError);
       video.remove();
       URL.revokeObjectURL(url);
    };

    video.addEventListener('seeked', onSeeked);
    video.addEventListener('error', onError);
    setTimeout(() => {
       resolve(createFallbackThumbnail('Video'));
       cleanup();
    }, 3000);
  });
};

const buildFilterString = (filterPreset: string, adj: VideoAdjustments): string => {
  let s = filterPreset !== 'none' ? `${filterPreset} ` : '';
  s += `brightness(${adj.brightness}%) `;
  s += `contrast(${adj.contrast}%) `;
  s += `saturate(${adj.saturation}%) `;
  s += `hue-rotate(${adj.hue}deg)`;
  return s;
};

const buildTransformString = (t: VideoTransform): string => {
  return `rotate(${t.rotate}deg) scaleX(${t.flipH ? -1 : 1}) scaleY(${t.flipV ? -1 : 1})`;
};

// --- VLC Style Player Component ---
const VLCPlayer: React.FC<{
  src: string;
  poster?: string;
  className?: string;
  style?: React.CSSProperties;
  shouldPlay?: boolean;
  muted?: boolean;
  loop?: boolean;
  onClick?: (e: React.MouseEvent) => void;
  onTimeUpdate?: () => void;
  onError?: (e: React.SyntheticEvent<HTMLVideoElement, Event>) => void;
  videoRef?: React.RefObject<HTMLVideoElement>;
  trim?: { start: number; end: number };
  audioLayers?: AudioLayer[];
}> = ({ src, poster, className, style, shouldPlay, muted, loop, onClick, onTimeUpdate, onError, videoRef, trim, audioLayers }) => {
  const localRef = useRef<HTMLVideoElement>(null);
  const ref = videoRef || localRef;
  const audioRefs = useRef<HTMLAudioElement[]>([]);

  const [isPlaying, setIsPlaying] = useState(false);
  const [isBuffering, setIsBuffering] = useState(true);
  const [progress, setProgress] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  useEffect(() => {
    if (isPlaying) {
      audioRefs.current.forEach(a => a?.play().catch(() => {}));
    } else {
      audioRefs.current.forEach(a => a?.pause());
    }
  }, [isPlaying]);

  useEffect(() => {
    audioRefs.current.forEach(a => {
      if (a && Math.abs(a.currentTime - currentTime) > 0.3) {
        a.currentTime = currentTime;
      }
    });
  }, [currentTime]);

  useEffect(() => {
    const video = ref.current;
    if (!video || !src) return;

    if (shouldPlay) {
      const playPromise = video.play();
      if (playPromise !== undefined) {
        playPromise
          .then(() => setIsPlaying(true))
          .catch(() => {
            setIsPlaying(false);
            video.muted = true;
            video.play().then(() => setIsPlaying(true)).catch(() => {});
          });
      }
    } else {
      video.pause();
      setIsPlaying(false);
    }
  }, [shouldPlay, ref, src]);

  useEffect(() => {
    const video = ref.current;
    if (!video) return;

    const handleWaiting = () => setIsBuffering(true);
    const handlePlaying = () => {
      setIsBuffering(false);
      setIsPlaying(true);
    };
    const handlePause = () => setIsPlaying(false);
    const handleLoadedMetadata = () => {
       setDuration(video.duration);
    };

    const handleTimeUpdate = () => {
      const current = video.currentTime;
      const dur = video.duration || 1;
      setCurrentTime(current);
      setDuration(dur);

      if (trim) {
        if (current < trim.start) video.currentTime = trim.start;
        if (current > trim.end) {
          if (loop) video.currentTime = trim.start;
          else {
            video.pause();
            setIsPlaying(false);
          }
        }
        const trimDuration = trim.end - trim.start;
        const trimCurrent = Math.max(0, current - trim.start);
        setProgress((trimCurrent / trimDuration) * 100);
      } else {
        setProgress((current / dur) * 100);
      }

      if (onTimeUpdate) onTimeUpdate();
    };

    video.addEventListener('waiting', handleWaiting);
    video.addEventListener('playing', handlePlaying);
    video.addEventListener('pause', handlePause);
    video.addEventListener('timeupdate', handleTimeUpdate);
    video.addEventListener('loadedmetadata', handleLoadedMetadata);

    return () => {
      video.removeEventListener('waiting', handleWaiting);
      video.removeEventListener('playing', handlePlaying);
      video.removeEventListener('pause', handlePause);
      video.removeEventListener('timeupdate', handleTimeUpdate);
      video.removeEventListener('loadedmetadata', handleLoadedMetadata);
    };
  }, [ref, trim, loop, onTimeUpdate]);

  const togglePlay = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!ref.current) return;
    if (isPlaying) ref.current.pause();
    else ref.current.play();
    if (onClick) onClick(e);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.stopPropagation();
    if (!ref.current) return;
    const pct = parseFloat(e.target.value);
    const d = ref.current.duration;
    if (trim) {
      const trimDur = trim.end - trim.start;
      ref.current.currentTime = trim.start + (trimDur * (pct / 100));
    } else {
      ref.current.currentTime = d * (pct / 100);
    }
    setProgress(pct);
  };

  const togglePiP = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!ref.current) return;
    try {
      if (document.pictureInPictureElement) await document.exitPictureInPicture();
      else await ref.current.requestPictureInPicture();
    } catch (e) { console.error("PiP Error", e); }
  };

  const formatTime = (time: number) => {
     const m = Math.floor(time / 60);
     const s = Math.floor(time % 60);
     return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  if (!src) return null;

  return (
    <div className="relative w-full h-full bg-black group" onClick={togglePlay}>
      <video
        key={src}
        ref={ref}
        src={src}
        poster={poster}
        className={`w-full h-full object-contain ${className}`}
        style={style}
        playsInline
        muted={muted}
        loop={loop}
        onError={onError}
      />
      {audioLayers?.map((layer, idx) => (
        <audio key={layer.id} ref={el => { if (el) audioRefs.current[idx] = el; }} src={layer.url} loop={loop} />
      ))}
      {!isPlaying && !isBuffering && (
        <div className="absolute inset-0 flex items-center justify-center z-10 bg-black/40 backdrop-blur-[2px]">
          <div className="flex flex-col items-center animate-bounce-slow">
             <Cone size={80} className="text-primary fill-primary drop-shadow-2xl" strokeWidth={1.5} />
             <div className="mt-4 flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-primary"></div>
                <h2 className="text-white font-bold text-xl tracking-wider drop-shadow-md">VLC Media Player</h2>
             </div>
          </div>
        </div>
      )}
      {isBuffering && shouldPlay && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-20">
          <Loader2 className="w-16 h-16 animate-spin text-primary" />
        </div>
      )}
      <div className="absolute bottom-0 left-0 right-0 bg-[#2b2b2b]/95 px-4 py-2 flex flex-col gap-1 z-30 border-t border-gray-700 transition-opacity duration-300 opacity-0 group-hover:opacity-100">
         <div className="relative w-full h-4 flex items-center">
            <input type="range" min="0" max="100" step="0.1" value={progress || 0} onChange={handleSeek} onClick={(e) => e.stopPropagation()} className="absolute w-full h-full opacity-0 cursor-pointer z-20" />
            <div className="w-full h-1.5 bg-gray-600 rounded-full overflow-hidden">
               <div className="h-full bg-primary" style={{ width: `${progress}%` }}></div>
            </div>
            <div className="absolute w-3 h-3 bg-white rounded-full shadow-md z-10 pointer-events-none" style={{ left: `${progress}%`, transform: 'translateX(-50%)' }}></div>
         </div>
         <div className="flex items-center justify-between text-gray-300 text-xs font-mono">
            <div className="flex items-center gap-4">
               <button onClick={togglePlay} className="hover:text-white transition">
                  {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" />}
               </button>
               <div className="flex items-center gap-1">
                  <span>{formatTime(currentTime)}</span>
                  <span className="text-gray-500">/</span>
                  <span>{formatTime(duration)}</span>
               </div>
            </div>
            <div className="flex items-center gap-3">
               <Volume2 size={18} />
               <button onClick={togglePiP} className="hover:text-white"><PictureInPicture size={18} /></button>
            </div>
         </div>
      </div>
    </div>
  );
};

