const VideoCard: React.FC<{ 
  video: Video; 
  isActive: boolean; 
  onTogglePlay: () => void;
  user: UserType | undefined;
  onInteraction: (type: 'like' | 'share' | 'comment' | 'bookmark') => void;
  onReport: () => void;
  onRequestShare: () => void;
  lang: LanguageCode;
  isBookmarked: boolean;
}> = ({ video, isActive, onTogglePlay, user, onInteraction, onReport, onRequestShare, lang, isBookmarked }) => {
  const [liked, setLiked] = useState(false);
  const [bookmarked, setBookmarked] = useState(isBookmarked);
  const [hasError, setHasError] = useState(false);
  const [showHeartAnimation, setShowHeartAnimation] = useState(false);
  const lastTapRef = useRef<number>(0);
  const t = TRANSLATIONS[lang];

  useEffect(() => { setHasError(false); }, [video.id]);

  const handleDoubleTap = (e: React.MouseEvent) => {
    const now = Date.now();
    if (now - lastTapRef.current < 300) {
      if (!liked) { setLiked(true); onInteraction('like'); }
      setShowHeartAnimation(true);
      setTimeout(() => setShowHeartAnimation(false), 1000);
    } 
    lastTapRef.current = now;
  };

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    setLiked(!liked);
    if (!liked) onInteraction('like');
  };

  const handleBookmark = (e: React.MouseEvent) => {
    e.stopPropagation();
    setBookmarked(!bookmarked);
    onInteraction('bookmark');
  };

  const handleError = () => setHasError(true);

  const handleNativeShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Videos App',
          text: video.description || 'Check out this video!',
          url: APP_SHARE_URL
        });
        onInteraction('share');
      } catch (err) {
        console.error("Share failed", err);
        onRequestShare(); // Fallback to custom share
      }
    } else {
      onRequestShare();
    }
  };

  if (hasError || !video.url) {
    return (
      <div className="relative w-full h-full snap-center bg-gray-900 flex flex-col items-center justify-center text-white p-6 text-center">
        <div className="w-16 h-16 bg-primary/20 rounded-full flex items-center justify-center mb-4">
           <AlertCircle size={32} className="text-primary" />
        </div>
        <h3 className="text-lg font-bold">Video Unavailable</h3>
        <p className="text-xs text-gray-500 mt-2">Expired source or unsupported format</p>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full snap-center bg-black overflow-hidden" onClick={handleDoubleTap}>
      {showHeartAnimation && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30 animate-bounce">
            <Heart size={100} className="text-white fill-red-500 drop-shadow-2xl opacity-90" />
         </div>
      )}
      <div className="w-full h-full">
        <VLCPlayer
          src={video.url}
          poster={video.thumbnail}
          shouldPlay={isActive}
          className="w-full h-full"
          style={{ 
            filter: video.editData ? buildFilterString(video.editData.filter, video.editData.adjustments) : 'none',
            transform: video.editData ? buildTransformString(video.editData.transform) : 'none'
          }}
          trim={video.editData?.trim}
          audioLayers={video.editData?.audioLayers}
          loop={true}
          onError={handleError}
        />
        {video.editData?.textLayers?.map((layer) => (
          <div key={layer.id} className="absolute pointer-events-none whitespace-nowrap z-10" style={{ top: `${layer.y}%`, left: `${layer.x}%`, transform: 'translate(-50%, -50%)', color: layer.color, fontSize: `${layer.fontSize}px`, textShadow: '1px 1px 2px black', backgroundColor: layer.backgroundColor || 'transparent', padding: '4px 8px', borderRadius: '4px' }}>
            <span className="font-bold">{layer.text}</span>
          </div>
        ))}
      </div>
      {video.hasWatermark && (!user || !user.isPremium) && (
        <div className="absolute top-20 right-4 z-20 bg-black/60 backdrop-blur-md px-3 py-1 rounded-full border border-white/20 pointer-events-none">
          <div className="flex items-center gap-1.5">
            <Sparkles size={12} className="text-primary" />
            <span className="text-[10px] text-white font-medium">{t.watermark}</span>
          </div>
        </div>
      )}
      <div className="absolute bottom-[20px] left-0 right-0 p-4 pointer-events-none z-20">
        <div className="flex justify-between items-end pb-12">
          <div className="text-white flex-1 mr-12 rtl:mr-0 rtl:ml-12 text-left rtl:text-right drop-shadow-md">
            <div className="flex items-center gap-2 mb-2">
                <h3 className="font-bold text-lg cursor-pointer hover:underline">@{user?.username || 'unknown'}</h3>
                {user?.isVerified && <span className="bg-blue-500 text-[10px] px-1 rounded-full text-white">✓</span>}
            </div>
            <p className="text-sm line-clamp-2 mb-2">{video.description}</p>
            <div className="flex gap-2 text-xs opacity-90 mb-2 flex-wrap">
               {video.tags.map(t => <span key={t} className="font-bold text-primary">#{t}</span>)}
            </div>
          </div>
          <div className="flex flex-col gap-6 items-center min-w-[50px] pointer-events-auto">
            <div className="relative group cursor-pointer">
               <img src={user?.avatar || createFallbackThumbnail('User')} alt="avatar" className="w-12 h-12 rounded-full border-2 border-white object-cover" />
            </div>
            <button onClick={handleLike} className="flex flex-col items-center gap-1 group">
              <div className={`p-2 transition transform active:scale-90 ${liked ? 'text-red-500' : 'text-white'}`}>
                <Heart fill={liked ? "currentColor" : "white"} size={32} className={liked ? "" : "opacity-90"} />
              </div>
              <span className="text-white text-xs font-bold drop-shadow-md">{video.likes + (liked ? 1 : 0)}</span>
            </button>
            <button onClick={handleNativeShare} className="flex flex-col items-center gap-1 group">
               <div className="p-2 transition transform active:scale-90 text-white">
                 <Share2 size={32} fill="white" className="opacity-90" />
               </div>
               <span className="text-white text-xs font-bold drop-shadow-md">{video.shares}</span>
            </button>
            <button onClick={handleBookmark} className="flex flex-col items-center gap-1 group">
               <div className={`p-2 transition transform active:scale-90 ${bookmarked ? 'text-yellow-400' : 'text-white'}`}>
                 <Bookmark size={32} fill={bookmarked ? "currentColor" : "none"} className="opacity-90" />
               </div>
            </button>
            <button onClick={onReport} className="flex flex-col items-center gap-1 group opacity-60 hover:opacity-100">
               <div className="p-2 text-white"><Flag size={20} /></div>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Auth Screen Component ---
const AuthScreen: React.FC<{ onLogin: (u: UserType) => void, lang: LanguageCode, setLang: (l: LanguageCode) => void }> = ({ onLogin, lang, setLang }) => {
   const [form, setForm] = useState({
     fullName: '', username: '', email: '', password: '', dob: '', gender: 'Other' as UserType['gender'], location: '', avatar: ''
   });
   const [detecting, setDetecting] = useState(false);
   const t = TRANSLATIONS[lang];

   const handleLocation = () => {
     setDetecting(true);
     navigator.geolocation.getCurrentPosition(
       (pos) => {
         setForm({ ...form, location: `${pos.coords.latitude.toFixed(2)}, ${pos.coords.longitude.toFixed(2)}` });
         setDetecting(false);
       },
       () => setDetecting(false)
     );
   };

   const handlePhoto = async (e: React.ChangeEvent<HTMLInputElement>) => {
     if (e.target.files?.[0]) {
       const reader = new FileReader();
       reader.onload = (ev) => setForm({ ...form, avatar: ev.target?.result as string });
       reader.readAsDataURL(e.target.files[0]);
     }
   };

   const handleSubmit = (e: React.FormEvent) => {
     e.preventDefault();
     if (!form.username || !form.fullName) return;
     onLogin({
       id: Math.random().toString(36).substr(2, 9),
       ...form,
       points: 100,
       isVerified: false,
       videoCount: 0,
       isPremium: false,
       bookmarks: []
     });
   };

   return (
     <div className="h-full flex flex-col items-center bg-white dark:bg-black overflow-y-auto px-6 py-10">
        <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mb-4 shadow-xl shadow-primary/30">
           <Play size={32} fill="white" className="ml-1" />
        </div>
        <h1 className="text-2xl font-bold text-primary mb-2">Videos</h1>
        <p className="text-gray-500 text-sm mb-8">{t.welcome}</p>

        <form onSubmit={handleSubmit} className="w-full max-w-sm space-y-4">
           <div className="flex justify-center mb-6">
              <label className="relative cursor-pointer group">
                 <div className="w-24 h-24 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center overflow-hidden border-2 border-primary/20 group-hover:border-primary transition">
                    {form.avatar ? <img src={form.avatar} className="w-full h-full object-cover" /> : <Camera size={32} className="text-gray-400" />}
                 </div>
                 <div className="absolute bottom-0 right-0 bg-primary text-white p-1.5 rounded-full shadow-lg"><Plus size={16}/></div>
                 <input type="file" hidden accept="image/*" onChange={handlePhoto} />
              </label>
           </div>

           <div className="space-y-3">
              <div className="relative">
                 <User size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input value={form.fullName} onChange={e => setForm({...form, fullName: e.target.value})} placeholder={t.fullName} required className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="relative">
                 <AtSign size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input value={form.username} onChange={e => setForm({...form, username: e.target.value})} placeholder={t.username} required className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="relative">
                 <Mail size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} placeholder={t.email} required className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="relative">
                 <Calendar size={18} className="absolute left-3 top-3 text-gray-400" />
                 <input type="date" value={form.dob} onChange={e => setForm({...form, dob: e.target.value})} placeholder={t.dob} className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl focus:ring-2 focus:ring-primary outline-none text-sm" />
              </div>
              <div className="flex gap-2">
                 <select value={form.gender} onChange={e => setForm({...form, gender: e.target.value as any})} className="flex-1 px-4 py-2.5 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl outline-none text-sm">
                    <option value="Male">{t.male || 'Male'}</option>
                    <option value="Female">{t.female || 'Female'}</option>
                    <option value="Other">{t.other || 'Other'}</option>
                 </select>
                 <button type="button" onClick={handleLocation} className="p-2.5 bg-gray-100 dark:bg-gray-800 rounded-xl text-primary hover:bg-gray-200 transition">
                    {detecting ? <Loader2 size={20} className="animate-spin" /> : <MapPin size={20}/>}
                 </button>
              </div>
           </div>

           <button type="submit" className="w-full py-3.5 bg-primary text-white rounded-xl font-bold shadow-lg shadow-primary/20 hover:bg-blue-800 transition">
              {t.createAccount}
           </button>
        </form>

        <div className="mt-10">
           <select value={lang} onChange={e => setLang(e.target.value as any)} className="bg-gray-100 dark:bg-gray-800 px-4 py-2 rounded-full text-xs">
              {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.native}</option>)}
           </select>
        </div>
     </div>
   );
};

const AtSign = ({ size, className }: any) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <circle cx="12" cy="12" r="4"/><path d="M16 8v5a3 3 0 0 0 6 0v-1a10 10 0 1 0-3.92 7.94"/>
  </svg>
);

// --- Main App Component ---

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserType | undefined>(() => {
    const saved = localStorage.getItem('currentUser');
    if (!saved || saved === 'undefined') return undefined;
    try {
      return JSON.parse(saved);
    } catch (e) {
      console.warn("Auth initialization error", e);
      return undefined;
    }
  });

  const [videos, setVideos] = useState<Video[]>([]);
  const [activeTab, setActiveTab] = useState('home');
  const [showUploadMenu, setShowUploadMenu] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showAiGenerator, setShowAiGenerator] = useState(false);
  const [editorFile, setEditorFile] = useState<File | null>(null);
  const [selectedLanguage, setSelectedLanguage] = useState<LanguageCode>('en');
  const [aiIdeaPrompt, setAiIdeaPrompt] = useState<string | undefined>();

  const [aiPrompt, setAiPrompt] = useState('');
  const [aiStyle, setAiStyle] = useState('Cinematic');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [showPolicy, setShowPolicy] = useState<{title: string, content: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Mandatory API Key selection for Veo models on launch
  useEffect(() => {
    const enforceApiKeySelection = async () => {
      if (typeof window.aistudio !== 'undefined') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await window.aistudio.openSelectKey();
        }
      }
    };
    enforceApiKeySelection();
  }, []);

  useEffect(() => {
    const browserLang = navigator.language.split('-')[0] as LanguageCode;
    if (TRANSLATIONS[browserLang]) setSelectedLanguage(browserLang);
  }, []);

  useEffect(() => {
    document.documentElement.dir = selectedLanguage === 'ar' ? 'rtl' : 'ltr';
  }, [selectedLanguage]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [currentUser]);

  const handlePublishVideo = async (metadata: VideoEditingMetadata, isAI: boolean) => {
    if (!editorFile || !currentUser) return;
    try {
      const thumbnail = await generateThumbnail(editorFile);
      const blobUrl = URL.createObjectURL(editorFile); 
      const newVideo: Video = {
        id: Date.now().toString(),
        userId: currentUser.id,
        url: blobUrl,
        thumbnail,
        type: 'short',
        description: aiIdeaPrompt || (isAI ? "AI Generated Masterpiece" : "My awesome new video"),
        views: 0, likes: 0, shares: 0, commentsCount: 0,
        tags: isAI ? ['AI', 'Generated'] : ['New', 'Creative'],
        createdAt: new Date().toISOString(),
        editData: { ...metadata, isAIGenerated: isAI },
        hasWatermark: isAI
      };
      setVideos(prev => [newVideo, ...prev]);
      setCurrentUser({ ...currentUser, videoCount: currentUser.videoCount + 1, points: currentUser.points + (isAI ? 5 : 10) });
      setShowEditor(false);
      setEditorFile(null);
      setAiIdeaPrompt(undefined);
    } catch (e) { console.error("Publishing error", e); }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (!file.type.startsWith('video/')) {
        alert("Please select a valid video file.");
        return;
      }
      setEditorFile(file);
      setShowEditor(true);
      setShowUploadMenu(false);
      e.target.value = '';
    }
  };

  if (!currentUser) {
    return <AuthScreen onLogin={setCurrentUser} lang={selectedLanguage} setLang={setSelectedLanguage} />;
  }

  return (
    <div className="flex flex-col h-screen bg-white dark:bg-black text-gray-900 dark:text-gray-100 overflow-hidden">
      {activeTab === 'home' && (
        <header className="absolute top-0 left-0 right-0 z-40 p-4 bg-gradient-to-b from-black/80 to-transparent flex justify-between items-center text-white">
           <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center"><Play size={16} fill="white" /></div>
              <span className="font-bold text-lg tracking-tight">Videos</span>
           </div>
           <div className="flex gap-4"><button><Search size={24} /></button><button><Bell size={24} /></button></div>
        </header>
      )}

      <main className="flex-1 overflow-hidden relative">
        {activeTab === 'home' && (
          <div className="h-full w-full snap-y-mandatory overflow-y-scroll no-scrollbar">
            {videos.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-500 gap-4 p-10 text-center">
                  <div className="w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center animate-pulse"><Play size={40} className="text-primary ml-1" /></div>
                  <p>{TRANSLATIONS[selectedLanguage].noVideos}</p>
                  <button onClick={() => setShowUploadMenu(true)} className="px-6 py-2 bg-primary text-white rounded-full font-bold shadow-lg">{TRANSLATIONS[selectedLanguage].beFirst}</button>
               </div>
            ) : (
              videos.map((v) => (
                <div key={v.id} className="h-full w-full snap-center">
                   <VideoCard video={v} isActive={true} onTogglePlay={() => {}} user={currentUser} onInteraction={() => {}} onReport={() => {}} onRequestShare={() => {}} lang={selectedLanguage} isBookmarked={currentUser.bookmarks?.includes(v.id)} />
                </div>
              ))
            )}
          </div>
        )}
        {activeTab === 'discover' && <div className="h-full overflow-y-auto p-4 bg-gray-50 dark:bg-black text-center py-20"><Search size={48} className="mx-auto mb-2 opacity-50"/><p>{TRANSLATIONS[selectedLanguage].discover}</p></div>}
        {activeTab === 'profile' && <ProfilePage user={currentUser} videos={videos.filter(v => v.userId === currentUser.id)} lang={selectedLanguage} onLogout={() => setCurrentUser(undefined)} onShowPolicy={setShowPolicy} />}
        {activeTab === 'support' && <div className="h-full p-4 bg-gray-50 dark:bg-black overflow-y-auto"><Support userName={currentUser.username} /></div>}
      </main>

      <nav className="h-16 bg-white dark:bg-black border-t border-gray-200 dark:border-gray-800 flex justify-around items-center z-50">
         <NavBtn icon={Home} label={TRANSLATIONS[selectedLanguage].home} active={activeTab === 'home'} onClick={() => setActiveTab('home')} />
         <NavBtn icon={Search} label={TRANSLATIONS[selectedLanguage].search} active={activeTab === 'discover'} onClick={() => setActiveTab('discover')} />
         <div className="relative -top-4"><button onClick={() => setShowUploadMenu(true)} className="w-14 h-14 bg-gradient-to-tr from-primary to-blue-400 rounded-full flex items-center justify-center text-white shadow-lg"><Plus size={32} /></button></div>
         <NavBtn icon={HelpCircle} label={TRANSLATIONS[selectedLanguage].support} active={activeTab === 'support'} onClick={() => setActiveTab('support')} />
         <NavBtn icon={User} label={TRANSLATIONS[selectedLanguage].profile} active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} />
      </nav>

      {showUploadMenu && (
         <div className="fixed inset-0 z-[60] bg-black/80 flex items-end animate-fade-in">
            <div className="w-full bg-white dark:bg-card rounded-t-2xl p-6 pb-10 space-y-4">
               <div className="flex justify-between items-center mb-2"><h3 className="font-bold text-lg">{TRANSLATIONS[selectedLanguage].create}</h3><button onClick={() => setShowUploadMenu(false)}><X/></button></div>
               <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center gap-4 px-4"><div className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center text-white"><ImageIcon/></div><div className="text-left"><div className="font-bold">{TRANSLATIONS[selectedLanguage].uploadFromGallery}</div><div className="text-xs text-gray-500">Edit existing videos</div></div></button>
               <button onClick={() => { setShowUploadMenu(false); setShowAiGenerator(true); }} className="w-full py-4 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center gap-4 px-4"><div className="w-10 h-10 bg-purple-500 rounded-full flex items-center justify-center text-white"><Sparkles/></div><div className="text-left"><div className="font-bold">{TRANSLATIONS[selectedLanguage].generateAiVideo}</div><div className="text-xs text-gray-500">Create from text prompt</div></div></button>
               <input type="file" ref={fileInputRef} className="hidden" accept="video/*" onChange={handleFileSelect} />
            </div>
         </div>
      )}

      {showEditor && editorFile && (
         <VideoEditor file={editorFile} onSave={handlePublishVideo} onCancel={() => { setShowEditor(false); setEditorFile(null); }} lang={selectedLanguage} initialPrompt={aiIdeaPrompt} />
      )}

      {showAiGenerator && (
         <div className="fixed inset-0 z-[60] bg-black/90 flex items-center justify-center p-4">
            <div className="bg-[#1E1E1E] w-full max-w-md rounded-2xl p-6 border border-gray-800 text-center">
               <Sparkles size={48} className="mx-auto mb-4 text-primary animate-pulse"/><h2 className="text-xl font-bold mb-2 text-white">{TRANSLATIONS[selectedLanguage].generateAiVideo}</h2>
               <textarea value={aiPrompt} onChange={(e) => setAiPrompt(e.target.value)} placeholder={TRANSLATIONS[selectedLanguage].enterPrompt} className="w-full bg-black/50 border border-gray-700 rounded-xl p-3 text-white mb-4 focus:border-primary outline-none" rows={3} />
               <div className="flex gap-2 mb-6 overflow-x-auto pb-2 no-scrollbar justify-center">
                  {['Cinematic', 'Cartoon', 'Realistic', 'Cyberpunk'].map(s => (<button key={s} onClick={() => setAiStyle(s)} className={`px-3 py-1 rounded-full text-xs border ${aiStyle === s ? 'bg-primary border-primary text-white' : 'border-gray-600 text-gray-400'}`}>{TRANSLATIONS[selectedLanguage][s.toLowerCase()] || s}</button>))}
