// --- VLC Style Player ---
const VLCPlayer: React.FC<{
  src: string;
  poster?: string;
  shouldPlay?: boolean;
  muted?: boolean;
  loop?: boolean;
  className?: string;
  style?: React.CSSProperties;
  audioLayers?: AudioLayer[];
  onError?: () => void;
}> = ({ src, poster, shouldPlay, muted, loop, className, style, audioLayers, onError }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isBuffering, setIsBuffering] = useState(true);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    if (shouldPlay) {
      video.play().catch(() => {
        video.muted = true;
        video.play().catch(console.error);
      });
    } else {
      video.pause();
    }
  }, [shouldPlay, src]);

  const togglePlay = (e: React.MouseEvent) => {
    e.stopPropagation();
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) video.play();
    else video.pause();
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const pct = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setProgress(pct);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.stopPropagation();
    if (videoRef.current) {
      const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
      videoRef.current.currentTime = time;
    }
  };

  return (
    <div className="relative w-full h-full bg-black group overflow-hidden" onClick={togglePlay}>
      <video
        ref={videoRef}
        src={src}
        poster={poster}
        className={`w-full h-full object-contain ${className}`}
        style={style}
        playsInline
        muted={muted}
        loop={loop}
        onWaiting={() => setIsBuffering(true)}
        onPlaying={() => { setIsBuffering(false); setIsPlaying(true); }}
        onPause={() => setIsPlaying(false)}
        onTimeUpdate={handleTimeUpdate}
        onError={onError}
      />

      {isBuffering && shouldPlay && (
        <div className="absolute inset-0 flex items-center justify-center z-20">
          <Loader2 className="w-12 h-12 animate-spin text-primary" />
        </div>
      )}

      {!isPlaying && !isBuffering && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/40 z-10">
          <div className="flex flex-col items-center">
             <Cone size={64} className="text-primary fill-primary animate-pulse" />
             <span className="text-white font-bold mt-2 text-sm tracking-widest">VLC</span>
          </div>
        </div>
      )}

      {/* Controls */}
      <div className="absolute bottom-0 left-0 right-0 p-3 bg-gradient-to-t from-black/80 to-transparent opacity-0 group-hover:opacity-100 transition-opacity">
        <div className="flex flex-col gap-2">
           <input 
             type="range" 
             min="0" max="100" step="0.1" 
             value={progress || 0} 
             onChange={handleSeek} 
             onClick={e => e.stopPropagation()}
             className="w-full h-1 bg-gray-600 rounded-full appearance-none cursor-pointer accent-primary"
           />
           <div className="flex items-center justify-between text-white text-xs">
              <button onClick={togglePlay}>{isPlaying ? <Pause size={18}/> : <Play size={18}/>}</button>
              <div className="flex gap-3">
                 <Volume2 size={16}/>
                 <PictureInPicture size={16}/>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

