  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isBuffering, setIsBuffering] = useState(true);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handlePlay = async () => {
      try {
        if (shouldPlay) {
          await video.play();
        } else {
          video.pause();
        }
      } catch (err) {
        if (shouldPlay) {
          video.muted = true;
          video.play().catch(() => {});
        }
      }
    };

    handlePlay();
  }, [shouldPlay, src]);

  const togglePlay = (e: React.MouseEvent) => {
    e.stopPropagation();
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) video.play().catch(() => {});
    else video.pause();
  };

  const handleTimeUpdate = () => {
    if (videoRef.current && videoRef.current.duration) {
      const pct = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setProgress(pct);
    }
  };

  return (
    <div className="relative w-full h-full bg-black group overflow-hidden" onClick={togglePlay}>
      <video
        ref={videoRef}
        src={src}
        poster={poster}
        className={`w-full h-full object-contain ${className}`}
        playsInline
        muted={muted}
        loop={loop}
        onWaiting={() => setIsBuffering(true)}
        onPlaying={() => { setIsBuffering(false); setIsPlaying(true); }}
        onPause={() => setIsPlaying(false)}
        onTimeUpdate={handleTimeUpdate}
        onError={onError}
      />

      {isBuffering && shouldPlay && (
        <div className="absolute inset-0 flex items-center justify-center z-20">
          <Loader2 className="w-12 h-12 animate-spin text-primary" />
        </div>
      )}

      {!isPlaying && !isBuffering && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/40 z-10 pointer-events-none">
          <div className="flex flex-col items-center">
             <Cone size={64} className="text-primary fill-primary animate-pulse" />
             <span className="text-white font-black mt-2 text-xs tracking-[0.3em]">VLC</span>
          </div>
        </div>
      )}

      {/* Progress Bar Overlay */}
      <div className="absolute bottom-0 left-0 right-0 h-1.5 bg-gray-800 z-30 overflow-hidden">
        <div 
          className="h-full bg-primary transition-all duration-150 ease-linear shadow-[0_0_8px_rgba(1,54,104,0.8)]" 
          style={{ width: `${progress}%` }} 
        />
      </div>
    </div>
  );
};

