        <div className="space-y-3">
          <div className="relative"><User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input value={form.fullName} onChange={e => setForm({...form, fullName: e.target.value})} placeholder={t.fullName} required className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm transition shadow-sm" /></div>
          <div className="relative"><AtSign size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input value={form.username} onChange={e => setForm({...form, username: e.target.value})} placeholder={t.username} required className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm transition shadow-sm" /></div>
