        <div className="relative -top-8">
           <button onClick={() => setActiveTab('studio')} className="w-20 h-20 bg-primary text-white rounded-[2.5rem] flex items-center justify-center shadow-2xl rotate-[15deg] transition-all active:scale-90 border-4 border-white dark:border-black"><Plus size={40} /></button>
