// --- Multi-Step Auth Screen ---
const AuthScreen: React.FC<{ 
  onLogin: (u: UserType) => void, 
  lang: LanguageCode, 
  onShowPolicy: (type: 'privacy' | 'terms') => void
}> = ({ onLogin, lang, onShowPolicy }) => {
  const [isLoginMode, setIsLoginMode] = useState(false);
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({ fullName: '', username: '', email: '', avatar: '', password: '', interests: [] as string[] });
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = TRANSLATIONS[lang] || TRANSLATIONS['en'];

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm({ ...form, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const toggleInterest = (id: string) => {
    setForm(prev => ({
      ...prev,
      interests: prev.interests.includes(id) 
        ? prev.interests.filter(i => i !== id) 
        : [...prev.interests, id]
    }));
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const data = getLocalData();
    const user = data.users.find((u: UserType) => (u.email === form.email || u.username === form.email) && u.password === form.password);

    if (user) {
      onLogin(user);
    } else {
      setError(t.invalidLogin);
    }
  };

  const nextStep = () => {
    if (step === 1) {
      if (!form.fullName || !form.username || !form.email) return setError("Please fill all fields");
      if (!form.avatar) return setError(t.photoRequired);
    }
    if (step === 2) {
      if (form.password.length < 6) return setError(t.passwordRequired);
    }
    setError(null);
    setStep(s => s + 1);
  };

  const handleFinish = () => {
    if (form.interests.length === 0) return setError(t.selectAtLeastOne);
    const user: UserType = {
      id: Math.random().toString(36).substr(2, 9),
      ...form,
      gender: 'Other', dob: '', location: '', points: 100,
      isVerified: false, videoCount: 0, isPremium: false, bookmarks: []
    };
    const data = getLocalData();
    data.users.push(user);
    saveLocalData(data);
    onLogin(user);
  };

  return (
    <div className="h-full flex flex-col items-center bg-white dark:bg-black overflow-y-auto px-8 py-10 no-scrollbar">
      <div className="text-center mb-8 animate-fade-in">
        <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30 rotate-3"><Play size={32} fill="white" className="ml-1" /></div>
        <h1 className="text-3xl font-black text-primary mb-1 tracking-tighter italic lowercase">videos</h1>
        <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.3em]">{isLoginMode ? t.login : `Step ${step} of 3`}</p>
      </div>

      <div className="w-full max-w-sm">
        {isLoginMode ? (
          <form onSubmit={handleLoginSubmit} className="space-y-4 animate-fade-in">
             <div className="relative">
               <Mail size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
               <input 
                value={form.email} onChange={e => setForm({...form, email: e.target.value})} 
                placeholder={t.email} required 
                className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" 
               />
             </div>
             <div className="relative">
               <Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
               <input 
                type={showPass ? 'text' : 'password'} value={form.password} onChange={e => setForm({...form, password: e.target.value})} 
                placeholder={t.password} required 
                className="w-full pl-12 pr-12 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" 
               />
               <button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400">{showPass ? <EyeOff size={18}/> : <Eye size={18}/>}</button>
             </div>
             <button type="submit" className="w-full py-5 bg-primary text-white rounded-2xl font-black shadow-2xl active:scale-95 transition-all uppercase tracking-widest text-sm">
               {t.login}
             </button>
             <p className="text-center text-[10px] text-gray-400 font-bold pt-4">
               Don't have an account? <button type="button" onClick={() => setIsLoginMode(false)} className="text-primary">{t.signUpNow}</button>
             </p>
          </form>
        ) : (
          <>
            {/* Progress Bar for SignUp */}
            <div className="flex items-center justify-between mb-8 px-4">
               {[1, 2, 3].map(s => (
                 <div key={s} className="flex items-center flex-1 last:flex-none">
                   <div className={`w-8 h-8 rounded-full flex items-center justify-center font-black text-xs transition-all ${step >= s ? 'bg-primary text-white shadow-lg' : 'bg-gray-100 text-gray-400'}`}>{step > s ? <Check size={16} strokeWidth={4} /> : s}</div>
                   {s < 3 && <div className={`h-1 flex-1 mx-2 rounded-full transition-all ${step > s ? 'bg-primary' : 'bg-gray-100'}`} />}
                 </div>
               ))}
            </div>

            {step === 1 && (
              <div className="space-y-6 animate-fade-in">
                <div className="flex flex-col items-center">
                  <div onClick={() => fileInputRef.current?.click()} className={`w-32 h-32 rounded-full border-4 cursor-pointer flex items-center justify-center overflow-hidden transition-all relative group ${form.avatar ? 'border-primary' : 'border-dashed border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 animate-pulse'}`}>
                    {form.avatar ? <img src={form.avatar} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center gap-1"><Camera size={32} className="text-gray-400" /><span className="text-[8px] font-black text-gray-400 uppercase">Avatar</span></div>}
                  </div>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFile} />
                </div>
                <div className="space-y-3">
                  <div className="relative"><User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input value={form.fullName} onChange={e => setForm({...form, fullName: e.target.value})} placeholder={t.fullName} className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" /></div>
                  <div className="relative"><AtSign size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input value={form.username} onChange={e => setForm({...form, username: e.target.value})} placeholder={t.username} className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" /></div>
                  <div className="relative"><Mail size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-primary" /><input value={form.email} onChange={e => setForm({...form, email: e.target.value})} placeholder={t.email} className="w-full pl-12 pr-4 py-4 bg-white dark:bg-gray-900 border-2 border-primary/20 focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-xl" /></div>
                </div>
                <button onClick={nextStep} className="w-full py-5 bg-primary text-white rounded-2xl font-black shadow-2xl active:scale-95 transition flex items-center justify-center gap-2 uppercase tracking-widest text-sm">{t.next} <ChevronRight size={18} /></button>
                <p className="text-center text-[10px] text-gray-400 font-bold mt-4">{t.alreadyHaveAccount} <button onClick={() => setIsLoginMode(true)} className="text-primary underline">Login</button></p>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-6 animate-fade-in">
                <div className="relative"><Lock size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input type={showPass ? 'text' : 'password'} value={form.password} onChange={e => setForm({...form, password: e.target.value})} placeholder={t.password} className="w-full pl-12 pr-12 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" /><button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400">{showPass ? <EyeOff size={18}/> : <Eye size={18}/>}</button></div>
                <div className="p-4 bg-primary/5 rounded-3xl border border-primary/10"><p className="text-[10px] text-gray-500 font-bold leading-relaxed">{t.agreeTo} <button onClick={() => onShowPolicy('privacy')} className="text-primary hover:underline">{t.privacyPolicy}</button> {t.and} <button onClick={() => onShowPolicy('terms')} className="text-primary hover:underline">{t.termsOfUse}</button></p></div>
                <div className="flex gap-3"><button onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 text-gray-500 rounded-2xl font-black flex items-center justify-center gap-2 uppercase tracking-widest text-sm"><ChevronLeft size={18}/> {t.back}</button><button onClick={() => setStep(3)} className="flex-[2] py-5 bg-primary text-white rounded-2xl font-black shadow-2xl active:scale-95 transition flex items-center justify-center gap-2 uppercase tracking-widest text-sm">{t.next} <ChevronRight size={18}/></button></div>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-6 animate-fade-in">
                <h2 className="text-center font-black text-xl italic uppercase text-gray-800 dark:text-gray-200">{t.selectInterests}</h2>
                <div className="grid grid-cols-2 gap-3 max-h-[40vh] overflow-y-auto no-scrollbar pr-1">{INTEREST_OPTIONS.map(opt => (<button key={opt.id} onClick={() => toggleInterest(opt.id)} className={`p-4 rounded-[2rem] border-2 transition-all flex flex-col items-center gap-2 ${form.interests.includes(opt.id) ? 'bg-primary border-primary text-white shadow-lg rotate-1' : 'bg-gray-50 dark:bg-gray-900 border-transparent text-gray-400 hover:border-gray-200'}`}><span className="text-2xl">{opt.icon}</span><span className="text-[10px] font-black uppercase tracking-tighter">{lang === 'ar' ? opt.ar : opt.label}</span></button>))}</div>
                <div className="flex gap-3"><button onClick={() => setStep(2)} className="flex-1 py-5 bg-gray-100 text-gray-500 rounded-2xl font-black flex items-center justify-center gap-2 uppercase tracking-widest text-sm"><ChevronLeft size={18}/> {t.back}</button><button onClick={handleFinish} className="flex-[2] py-5 bg-primary text-white rounded-2xl font-black shadow-2xl active:scale-95 transition flex items-center justify-center gap-2 uppercase tracking-widest text-sm">{t.finish}</button></div>
              </div>
            )}
          </>
        )}

        {error && <p className="mt-6 text-red-500 text-[10px] font-black text-center animate-bounce uppercase">{error}</p>}
      </div>
    </div>
  );
};

// --- Main App Component ---
const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserType | undefined>(() => {
    const saved = localStorage.getItem('currentUser');
    return (saved && saved !== 'undefined') ? JSON.parse(saved) : undefined;
  });
  const [activeTab, setActiveTab] = useState('home');
  const [lang, setLang] = useState<LanguageCode>('en');
  const [videos, setVideos] = useState<Video[]>(() => getLocalData().videos);
  const [showPolicy, setShowPolicy] = useState<{ title: string; content: string } | null>(null);

  useEffect(() => {
    if (currentUser) localStorage.setItem('currentUser', JSON.stringify(currentUser));
    else localStorage.removeItem('currentUser');
  }, [currentUser]);

