                    <div className="absolute right-4 bottom-28 flex flex-col gap-8 items-center">
                       <button className="p-4 bg-black/40 backdrop-blur-2xl rounded-3xl text-white active:scale-90 border border-white/20 shadow-2xl"><Heart size={28}/></button>
                       <button className="p-4 bg-black/40 backdrop-blur-2xl rounded-3xl text-white active:scale-90 border border-white/20 shadow-2xl"><Share2 size={28}/></button>
