                </button>

                <button onClick={() => handleShowPolicy('privacy')} className="w-full flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-900 rounded-3xl transition-all hover:bg-primary/5">
                  <div className="flex items-center gap-3"><ShieldCheck size={20} className="text-primary" /><span className="text-sm font-black uppercase tracking-tighter">{t.privacyPolicy}</span></div>
                  <ChevronRight size={16} className={`text-gray-400 ${lang === 'ar' ? 'rotate-180' : ''}`} />
                </button>
                <button onClick={() => handleShowPolicy('terms')} className="w-full flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-900 rounded-3xl transition-all hover:bg-primary/5">
                  <div className="flex items-center gap-3"><FileText size={20} className="text-primary" /><span className="text-sm font-black uppercase tracking-tighter">{t.termsOfUse}</span></div>
                  <ChevronRight size={16} className={`text-gray-400 ${lang === 'ar' ? 'rotate-180' : ''}`} />
                </button>
                <button onClick={() => setCurrentUser(undefined)} className="w-full mt-6 p-5 bg-red-600/10 text-red-600 rounded-3xl font-black uppercase tracking-widest text-xs border border-red-600/20 flex items-center justify-center gap-2">
                   <LogOut size={16}/> Sign Out
