        )}
      </main>

      <nav className="h-24 bg-white dark:bg-black border-t-2 dark:border-gray-900 flex justify-around items-center px-4 pb-6">
        <NavBtn icon={Home} label={t.home} active={activeTab === 'home'} onClick={() => setActiveTab('home')} />
        <NavBtn icon={Search} label={t.search} active={activeTab === 'explore'} onClick={() => setActiveTab('explore')} />
        <div className="relative -top-8">
           <button onClick={() => setActiveTab('studio')} className="w-20 h-20 bg-primary text-white rounded-[2.5rem] flex items-center justify-center shadow-2xl rotate-[15deg] transition-all active:scale-90 border-4 border-white dark:border-black"><Plus size={40} /></button>
