// --- Real Recording Studio Component ---
const StudioView: React.FC<{ onSave: (v: Video) => void, lang: LanguageCode, user: UserType }> = ({ onSave, lang, user }) => {
  const t = TRANSLATIONS[lang] || TRANSLATIONS['en'];
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [recordedChunks, setRecordedChunks] = useState<Blob[]>([]);
  const [aiIdeas, setAiIdeas] = useState<string[]>([]);
  const [loadingIdeas, setLoadingIdeas] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  // Metadata fields
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  useEffect(() => {
    let currentStream: MediaStream | null = null;
    async function initCamera() {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
        currentStream = s;
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      } catch (err) {
        console.error("Camera access error:", err);
      }
    }
    initCamera();
    return () => {
      if (currentStream) {
        currentStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [previewUrl]);

  const startRecording = () => {
    if (!stream) return;
    setRecordedChunks([]);
    const recorder = new MediaRecorder(stream);
    recorder.ondataavailable = (e) => {
      if (e.data.size > 0) setRecordedChunks(prev => [...prev, e.data]);
    };
    recorder.onstop = () => {
      // Logic handled in a state effect to ensure chunks are updated
    };
    recorder.start();
    mediaRecorderRef.current = recorder;
    setIsRecording(true);
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.onstop = () => {
        const blob = new Blob(recordedChunks, { type: 'video/mp4' });
        const url = URL.createObjectURL(blob);
        setPreviewUrl(url);
      };
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const handleFinalSave = () => {
    if (!previewUrl) return;
    const newVideo: Video = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      url: previewUrl,
      thumbnail: 'https://images.unsplash.com/photo-1485846234645-a62644f84728?auto=format&fit=crop&q=80&w=400',
      type: 'short',
      title: title.trim() || `Topic: ${new Date().toLocaleDateString()}`,
      description: description.trim() || 'Recorded interest',
      views: 0, likes: 0, shares: 0, commentsCount: 0,
      tags: ['daily', 'interest'],
      createdAt: new Date().toISOString()
    };
    onSave(newVideo);
    setPreviewUrl(null);
    setTitle('');
    setDescription('');
  };

  const fetchIdeas = async () => {
    setLoadingIdeas(true);
    const ideas = await getAIVideoIdeas(lang === 'ar' ? 'Arabic' : 'English');
    setAiIdeas(ideas);
    setLoadingIdeas(false);
  };

  if (previewUrl) {
    return (
      <div className="h-full bg-black flex flex-col p-6 animate-fade-in overflow-y-auto no-scrollbar">
        <div className="aspect-[9/16] w-full max-w-[320px] mx-auto rounded-[2.5rem] overflow-hidden border-4 border-white/10 shadow-2xl mb-6 flex-shrink-0">
          <video src={previewUrl} autoPlay loop muted playsInline className="w-full h-full object-cover" />
        </div>
        <div className="space-y-4 w-full max-w-md mx-auto">
           <input 
             value={title} onChange={e => setTitle(e.target.value)} 
             placeholder={t.videoTitle}
             className="w-full bg-white/5 border-2 border-white/10 p-4 rounded-2xl text-white font-bold outline-none focus:border-primary transition"
           />
           <textarea 
             value={description} onChange={e => setDescription(e.target.value)} 
             placeholder={t.videoDescription}
             rows={3}
             className="w-full bg-white/5 border-2 border-white/10 p-4 rounded-2xl text-white font-bold outline-none focus:border-primary transition resize-none"
           />
           <div className="flex gap-4 pt-4">
              <button 
                onClick={() => setPreviewUrl(null)} 
                className="flex-1 py-4 bg-gray-800 text-white font-black rounded-2xl uppercase tracking-widest text-xs active:scale-95 transition"
              >
                {t.discard}
              </button>
              <button 
                onClick={handleFinalSave} 
                className="flex-[2] py-4 bg-primary text-white font-black rounded-2xl uppercase tracking-widest text-xs shadow-xl active:scale-95 transition flex items-center justify-center gap-2"
              >
                <Check size={18} /> {t.savePost}
              </button>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full bg-black flex flex-col p-4 animate-fade-in">
      <div className="flex-1 rounded-[2.5rem] overflow-hidden bg-gray-900 relative shadow-2xl border-4 border-white/5">
        <video ref={videoRef} autoPlay muted playsInline className="w-full h-full object-cover scale-x-[-1]" />
        <div className="absolute top-6 left-6 flex items-center gap-2 bg-black/40 backdrop-blur-xl px-4 py-2 rounded-full border border-white/10">
           <div className={`w-2 h-2 rounded-full ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`} />
           <span className="text-white text-[10px] font-black uppercase tracking-widest">{isRecording ? 'Recording' : 'Ready'}</span>
        </div>
        <div className="absolute top-1/2 -translate-y-1/2 right-4 flex flex-col gap-3">
