          <div className="absolute bottom-32 left-6 right-6 bg-black/60 backdrop-blur-2xl p-4 rounded-3xl border border-white/10 animate-fade-in">
             <h4 className="text-primary text-[10px] font-black uppercase mb-2 tracking-widest flex items-center gap-2">
               <Zap size={12} fill="currentColor"/> {t.aiSuggestions}
             </h4>
