        {activeTab === 'support' && <Support userName={currentUser.username} />}
        {activeTab === 'profile' && (
          <div className="h-full overflow-y-auto pb-24 px-6 animate-fade-in">
             <div className="flex flex-col items-center pt-12">
                <img src={currentUser.avatar} className="w-32 h-32 rounded-[2.5rem] border-4 border-primary shadow-2xl rotate-2" />
                <h2 className="mt-6 font-black text-2xl uppercase italic">@{currentUser.username}</h2>
                <div className="flex gap-4 mt-4 overflow-x-auto no-scrollbar w-full justify-center">
                   {currentUser.interests.map(id => (
                     <span key={id} className="px-3 py-1 bg-primary/10 text-primary text-[8px] font-black uppercase tracking-widest rounded-full border border-primary/20">
