                <div className="flex gap-10 mt-6">
                   <div className="text-center font-black"><div>{videos.filter(v => v.userId === currentUser.id).length}</div><div className="text-[9px] text-gray-400 uppercase">topics</div></div>
                   <div className="text-center font-black"><div>{currentUser.points}</div><div className="text-[9px] text-gray-400 uppercase">points</div></div>
                </div>
             </div>

             <div className="mt-10 space-y-3">
                <button onClick={toggleLanguage} className="w-full flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-900 rounded-3xl transition-all hover:bg-primary/5">
