// --- Multi-Step Sign-Up Screen ---
const AuthScreen: React.FC<{ 
  onLogin: (u: UserType) => void, 
  lang: LanguageCode, 
  setLang: (l: LanguageCode) => void,
  onShowPolicy: (type: 'privacy' | 'terms') => void
}> = ({ onLogin, lang, setLang, onShowPolicy }) => {
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({ fullName: '', username: '', email: '', avatar: '', password: '', interests: [] as string[] });
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = TRANSLATIONS[lang] || TRANSLATIONS['en'];

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm({ ...form, avatar: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const toggleInterest = (id: string) => {
    setForm(prev => ({
      ...prev,
      interests: prev.interests.includes(id) 
        ? prev.interests.filter(i => i !== id) 
        : [...prev.interests, id]
    }));
  };

  const nextStep = () => {
    if (step === 1) {
      if (!form.fullName || !form.username || !form.email) return setError("Please fill all fields");
      if (!form.avatar) return setError(t.photoRequired);
    }
    if (step === 2) {
      if (form.password.length < 6) return setError(t.passwordRequired);
    }
    setError(null);
    setStep(s => s + 1);
  };

  const handleFinish = () => {
    if (form.interests.length === 0) return setError(t.selectAtLeastOne);
    const user: UserType = {
      id: Math.random().toString(36).substr(2, 9),
      ...form,
      gender: 'Other', dob: '', location: '', points: 100,
      isVerified: false, videoCount: 0, isPremium: false, bookmarks: []
    };
    const data = getLocalData();
    data.users.push(user);
    saveLocalData(data);
    onLogin(user);
  };

  return (
    <div className="h-full flex flex-col items-center bg-white dark:bg-black overflow-y-auto px-8 py-10 no-scrollbar relative">
      <div className="absolute top-6 right-6 flex gap-2">
         {LANGUAGES.map(l => (
           <button 
             key={l.code} 
             onClick={() => setLang(l.code as LanguageCode)}
             className={`px-3 py-1 rounded-full text-[10px] font-black uppercase transition-all ${lang === l.code ? 'bg-primary text-white shadow-lg' : 'bg-gray-100 text-gray-400'}`}
           >
             {l.code}
           </button>
         ))}
      </div>

      <div className="text-center mb-8 animate-fade-in mt-10">
        <h1 className="text-3xl font-black text-primary mb-1 tracking-tighter italic lowercase">videos</h1>
        <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.3em]">{t.createAccount} - Step {step} of 3</p>
      </div>

      <div className="w-full max-w-sm">
        <div className="flex items-center justify-between mb-8 px-4">
           {[1, 2, 3].map(s => (
             <div key={s} className="flex items-center flex-1 last:flex-none">
               <div className={`w-8 h-8 rounded-full flex items-center justify-center font-black text-xs transition-all ${step >= s ? 'bg-primary text-white shadow-lg' : 'bg-gray-100 text-gray-400'}`}>{step > s ? <Check size={16} strokeWidth={4} /> : s}</div>
               {s < 3 && <div className={`h-1 flex-1 mx-2 rounded-full transition-all ${step > s ? 'bg-primary' : 'bg-gray-100'}`} />}
             </div>
           ))}
        </div>

        {step === 1 && (
          <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col items-center">
              <div onClick={() => fileInputRef.current?.click()} className={`w-32 h-32 rounded-full border-4 cursor-pointer flex items-center justify-center overflow-hidden transition-all relative group ${form.avatar ? 'border-primary' : 'border-dashed border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 animate-pulse'}`}>
                {form.avatar ? <img src={form.avatar} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center gap-1"><Camera size={32} className="text-gray-400" /><span className="text-[8px] font-black text-gray-400 uppercase">Avatar</span></div>}
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFile} />
            </div>
            <div className="space-y-3">
              <div className="relative"><User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input value={form.fullName} onChange={e => setForm({...form, fullName: e.target.value})} placeholder={t.fullName} className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" /></div>
              <div className="relative"><AtSign size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" /><input value={form.username} onChange={e => setForm({...form, username: e.target.value})} placeholder={t.username} className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-sm" /></div>
              <div className="relative"><Mail size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-primary" /><input value={form.email} onChange={e => setForm({...form, email: e.target.value})} placeholder={t.email} className="w-full pl-12 pr-4 py-4 bg-white dark:bg-gray-900 border-2 border-primary/20 focus:border-primary rounded-2xl outline-none font-bold text-sm shadow-xl" /></div>
            </div>
